syntax = "proto2";
package demo;
message Good { optional string value = 1; }
message Bad { required string value = 1; }
service Echo {
  rpc Accepted(Good) returns (Good);
  rpc Excluded(Bad) returns (Good);
}

syntax = "proto3";
package demo;
message EchoRequest {}
service Echo { rpc Call(EchoRequest) returns (EchoRequest); }

syntax = "proto3";
package demo;
message EchoRequest {}
service Echo { rpc Call(EchoRequest) returns (EchoRequest); }
